#include <bits/stdc++.h>using namespace std; // --- FAST I/O & SHORTCUTS ---using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>; // Constantsconst ll MOD = 1e9 + 7;const ll INF = 1e18; // --- LOGIC ---void solve() {    ll n;    cin >> n;    map<ll, ll> freq;    for (ll i = 0; i < n; i++) {        ll x;        cin >> x;        freq[x]++;    }    ll max_freq = 0;    for (auto& p : freq) {        max_freq = max(max_freq, p.second);    }    ll clone=0;    while(max_freq<n){        clone++;        if(max_freq*2<=n){            clone+=max_freq;            max_freq*=2;        }        else{            clone+=(n-max_freq);            max_freq=n;        }    }    cout << clone << "\n";   } // --- MAIN DRIVER ---int main() {    // Fast I/O: 10x faster input reading    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int T = 1;    cin >> T; // Comment this out if problem has NO test cases    while (T--) {        solve();    }    return 0;}